/**
 * Canvas State Management
 *
 * Exports the canvas state machine and related utilities.
 *
 * Usage in components:
 * ```tsx
 * import { useCanvas, canvasActions } from '../state';
 *
 * function MyComponent() {
 *   // Get viewport state and actions
 *   const [viewport, actions] = useCanvas('viewport');
 *
 *   // Or use selector for specific values
 *   const camera = useCanvasSelector(s => s.viewport.camera);
 *
 *   // Update state
 *   actions.setCamera({ x: 100, y: 200 });
 * }
 * ```
 *
 * Usage in animation loops (outside React):
 * ```tsx
 * import { canvasStore, canvasActions } from '../state';
 *
 * function animate() {
 *   // Read current state synchronously
 *   const state = canvasStore.getState();
 *   const camera = state.viewport.camera;
 *
 *   // Update state
 *   canvasStore.dispatch(canvasActions.viewport.setCamera({ x: newX, y: newY }));
 *
 *   requestAnimationFrame(animate);
 * }
 * ```
 */

export {
  canvasMachine,
  useCanvas,
  useCanvasSelector,
  canvasActions,
  canvasStore,
} from './canvas-machine';

export type {
  CanvasState,
  ViewportSliceState,
  CameraPosition,
  MomentumState,
  AnimationState,
  CanvasSize,
  InteractionSliceState,
} from './canvas-machine';

export { viewportSlice } from './viewport';
export { interactionSlice } from './interaction';

/**
 * Canvas State Machine
 *
 * Central state management for the MMS Canvas using @zazcart/tools.
 * Uses useSyncExternalStore for React integration without stale closure issues.
 *
 * Slices:
 * - viewport: Camera position, momentum, animation, panning
 * - interaction: Hover and selection state for tasks
 *
 * @see TECH-DEBT-001
 * @see F018 - Hover highlight
 * @see F019 - Click to select
 */

import { createMachine } from '@zazcart/tools';
import { viewportSlice, type ViewportSliceState } from './viewport';
import { interactionSlice, type InteractionSliceState } from './interaction';

// ─────────────────────────────────────────────────────────────
// STATE TYPE
// ─────────────────────────────────────────────────────────────

/**
 * Full canvas state structure.
 * Used for type-safe selectors.
 */
export interface CanvasState {
  viewport: ViewportSliceState;
  interaction: InteractionSliceState;
}

// ─────────────────────────────────────────────────────────────
// CANVAS MACHINE
// ─────────────────────────────────────────────────────────────

export const canvasMachine = createMachine({
  id: 'canvas',
  slices: {
    viewport: viewportSlice,
    interaction: interactionSlice,
  },
  context: {
    userID: null,  // Canvas is public/anonymous, no user context needed
  },
  // Note: metadata tracking disabled via library defaults for 60fps performance
});

// ─────────────────────────────────────────────────────────────
// EXPORTS
// ─────────────────────────────────────────────────────────────

// Typed hooks for React components
export const useCanvas = canvasMachine.useMachine;

/**
 * Type-safe selector hook for canvas state.
 * Returns properly typed values instead of unknown.
 *
 * @example
 * const camera = useCanvasSelector(s => s.viewport.camera);
 * // camera is typed as CameraPosition
 */
export function useCanvasSelector<T>(selector: (state: CanvasState) => T): T {
  return canvasMachine.useSelector(selector as (state: unknown) => T);
}

// Actions for dispatching state changes
export const canvasActions = canvasMachine.actions;

// Direct store access for animation loops (no React re-render)
export const canvasStore = {
  getState: canvasMachine.getState as unknown as () => CanvasState,
  dispatch: canvasMachine.dispatch,
  subscribe: canvasMachine.subscribe,
};

// Re-export types (CanvasState already exported at definition)
export type { ViewportSliceState, CameraPosition, MomentumState, AnimationState, CanvasSize } from './viewport';
export type { InteractionSliceState } from './interaction';

