/**
 * Interaction State Slice
 *
 * Manages hover, selection, and focus state for task interactions.
 * Uses @zazcart/tools external store pattern for synchronous access.
 *
 * @see F018 - Hover highlight on tasks
 * @see F019 - Click to select task
 * @see F021 - Keyboard navigation for tasks
 */

import { createSyncSlice } from '@zazcart/tools';

// ─────────────────────────────────────────────────────────────
// STATE TYPES
// ─────────────────────────────────────────────────────────────

export interface InteractionSliceState {
  /** Currently hovered task ID (null if none) */
  hoveredTaskId: string | null;

  /** Mouse position in world coordinates (for hover detection) */
  mouseWorldPos: { x: number; y: number } | null;

  /** Currently selected task ID (null if none) - for F019 */
  selectedTaskId: string | null;

  /** Currently keyboard-focused task ID (null if none) - for F021 */
  focusedTaskId: string | null;

  /** Whether cursor is over a hoverable area */
  isHoverable: boolean;
}

// ─────────────────────────────────────────────────────────────
// INITIAL STATE
// ─────────────────────────────────────────────────────────────

const initialState: InteractionSliceState = {
  hoveredTaskId: null,
  mouseWorldPos: null,
  selectedTaskId: null,
  focusedTaskId: null,
  isHoverable: false,
};

// ─────────────────────────────────────────────────────────────
// INTERACTION SLICE
// ─────────────────────────────────────────────────────────────

// eslint-disable-next-line @typescript-eslint/no-explicit-any
export const interactionSlice = createSyncSlice({
  id: 'interaction',
  initial: initialState as any,  // TECH-DEBT-002: @zazcart/tools generic inference
  cache: { policy: 'session' },
  reducers: {
    // Hover state
    setHoveredTask(state: any, payload: string | null) {
      const s = state as InteractionSliceState;
      s.hoveredTaskId = payload;
      s.isHoverable = payload !== null;
    },

    setMouseWorldPos(
      state: any,
      payload: { x: number; y: number } | null
    ) {
      (state as InteractionSliceState).mouseWorldPos = payload;
    },

    clearHover(state: any) {
      const s = state as InteractionSliceState;
      s.hoveredTaskId = null;
      s.mouseWorldPos = null;
      s.isHoverable = false;
    },

    // Selection state (F019)
    setSelectedTask(state: any, payload: string | null) {
      (state as InteractionSliceState).selectedTaskId = payload;
    },

    clearSelection(state: any) {
      (state as InteractionSliceState).selectedTaskId = null;
    },

    // Focus state (F021 - keyboard navigation)
    setFocusedTask(state: any, payload: string | null) {
      (state as InteractionSliceState).focusedTaskId = payload;
    },

    clearFocus(state: any) {
      (state as InteractionSliceState).focusedTaskId = null;
    },

    // Reset all
    reset() {
      return initialState;
    },
  },
});

export type InteractionSlice = typeof interactionSlice;

