     1→/**
     2→ * InfiniteCanvas - Professional-grade pan/zoom canvas
     3→ *
     4→ * Features:
     5→ * - Pan with mouse drag (bounded to world limits)
     6→ * - Zoom with scroll wheel (centers on cursor position)
     7→ * - Initial view shows top-left of data (X=0, Y=0)
     8→ * - Sidebar sync via onViewportChange callback
     9→ *
    10→ * Coordinate System:
    11→ * - X: 0 = first day, positive = future (right)
    12→ * - Y: 0 = first train (TRAIN-001), negative = more trains (down)
    13→ *
    14→ * References:
    15→ * - D3.js zoom: https://d3js.org/d3-zoom
    16→ * - Three.js OrthographicCamera: https://threejs.org/docs/api/en/cameras/OrthographicCamera.html
    17→ * - pixi-viewport: https://github.com/pixijs-userland/pixi-viewport
    18→ */
    19→
    20→import { Canvas, useThree } from '@react-three/fiber';
    21→import { useCallback, useMemo, useEffect, useRef } from 'react';
    22→import { MesoLayer } from './layers/MesoLayer';
    23→import { MacroLayer } from './layers/MacroLayer';
    24→import { MicroLayer } from './layers/MicroLayer';
    25→import { PerfMonitor } from '../components/PerfMonitor';
    26→import type { PerfEvent } from '../components/PerfMonitor';
    27→import { getRenderData } from '../data/generator';
    28→import type { LODLevel, WorldBounds } from '../data/types';
    29→import { DEFAULT_VIEW_CONFIG, calculateWorldBounds } from '../data/types';
    30→import { useCanvasSelector, canvasActions, canvasStore } from '../state';
    31→import { useSpatialIndex, type ISpatialIndex } from '../spatial';
    32→
    33→// ─────────────────────────────────────────────────────────────
    34→// EXPORTED TYPES
    35→// ─────────────────────────────────────────────────────────────
    36→
    37→/**
    38→ * Viewport information passed to parent component
    39→ */
    40→export interface ViewportInfo {
    41→  /** Y coordinate of the TOP of the viewport in world space */
    42→  topY: number;
    43→  /** Left edge of the viewport in world X coordinates */
    44→  leftX: number;
    45→  /** Right edge of the viewport in world X coordinates */
    46→  rightX: number;
    47→}
    48→
    49→/**
    50→ * Viewport bounds in world coordinates
    51→ * Used for frustum culling - only render tasks within these bounds
    52→ */
    53→export interface ViewportBounds {
    54→  minX: number;
    55→  maxX: number;
    56→  minY: number;
    57→  maxY: number;
    58→}
    59→
    60→// ─────────────────────────────────────────────────────────────
    61→// LOD CONFIGURATION
    62→// ─────────────────────────────────────────────────────────────
    63→
    64→/**
    65→ * LOD Transition Configuration
    66→ *
    67→ * Defines blend zones around LOD thresholds for smooth transitions.
    68→ * During blend zones, both adjacent layers render with interpolated opacity.
    69→ */
    70→const LOD_THRESHOLDS = {
    71→  macroToMeso: 0.5,  // Below 0.5 = MACRO
    72→  mesoToMicro: 2.0,  // Above 2.0 = MICRO
    73→};
    74→
    75→// Size of blend zone around each threshold (±this value)
    76→const BLEND_ZONE_SIZE = 0.15;
    77→
    78→/**
    79→ * Calculate layer opacities for smooth LOD transitions
    80→ *
    81→ * Returns opacity values for each layer (0-1).
    82→ * During blend zones, adjacent layers overlap with interpolated opacity.
    83→ */
    84→function calculateLayerOpacities(zoom: number): {
    85→  macro: number;
    86→  meso: number;
    87→  micro: number;
    88→} {
    89→  const { macroToMeso, mesoToMicro } = LOD_THRESHOLDS;
    90→
    91→  // Define blend zone boundaries
    92→  const macroEnd = macroToMeso - BLEND_ZONE_SIZE; // 0.35
    93→  const mesoStart = macroToMeso + BLEND_ZONE_SIZE; // 0.65
    94→  const mesoEnd = mesoToMicro - BLEND_ZONE_SIZE; // 1.85
    95→  const microStart = mesoToMicro + BLEND_ZONE_SIZE; // 2.15
    96→
    97→  let macro = 0;
    98→  let meso = 0;
    99→  let micro = 0;
   100→
   101→  // Calculate MACRO opacity
   102→  if (zoom <= macroEnd) {
   103→    macro = 1;
   104→  } else if (zoom < mesoStart) {
   105→    // Blend zone MACRO → MESO
   106→    const t = (zoom - macroEnd) / (mesoStart - macroEnd);
   107→    macro = 1 - t;
   108→  }
   109→
   110→  // Calculate MESO opacity
   111→  if (zoom < macroEnd) {
   112→    meso = 0;
   113→  } else if (zoom < mesoStart) {
   114→    // Blend zone MACRO → MESO
   115→    const t = (zoom - macroEnd) / (mesoStart - macroEnd);
   116→    meso = t;
   117→  } else if (zoom <= mesoEnd) {
   118→    meso = 1;
   119→  } else if (zoom < microStart) {
   120→    // Blend zone MESO → MICRO
   121→    const t = (zoom - mesoEnd) / (microStart - mesoEnd);
   122→    meso = 1 - t;
   123→  }
   124→
   125→  // Calculate MICRO opacity
   126→  if (zoom <= mesoEnd) {
   127→    micro = 0;
   128→  } else if (zoom < microStart) {
   129→    // Blend zone MESO → MICRO
   130→    const t = (zoom - mesoEnd) / (microStart - mesoEnd);
   131→    micro = t;
   132→  } else {
   133→    micro = 1;
   134→  }
   135→
   136→  return { macro, meso, micro };
   137→}
   138→
   139→/**
   140→ * LODLayers - Orchestrates layer rendering with smooth transitions
   141→ *
   142→ * Renders multiple layers simultaneously during blend zones,
   143→ * with opacity interpolation for smooth visual transitions.
   144→ */
   145→function LODLayers({
   146→  tasks,
   147→  trainCount,
   148→  zoom,
   149→  viewportBounds,
   150→  spatialIndex,
   151→  hoveredTaskId,
   152→  selectedTaskId,
   153→  focusedTaskId,
   154→}: {
   155→  tasks: ReturnType<typeof getRenderData>['tasks'];
   156→  trainCount: number;
   157→  zoom: number;
   158→  viewportBounds: ViewportBounds;
   159→  spatialIndex: ISpatialIndex;
   160→  hoveredTaskId: string | null;
   161→  selectedTaskId: string | null;
   162→  focusedTaskId: string | null;
   163→}) {
   164→  const opacities = useMemo(() => calculateLayerOpacities(zoom), [zoom]);
   165→
   166→  return (
   167→    <group>
   168→      {/* Render each layer if opacity > 0 */}
   169→      {opacities.macro > 0 && (
   170→        <MacroLayer
   171→          tasks={tasks}
   172→          trainCount={trainCount}
   173→          opacity={opacities.macro}
   174→        />
   175→      )}
   176→      {opacities.meso > 0 && (
   177→        <MesoLayer
   178→          tasks={tasks}
   179→          trainCount={trainCount}
   180→          opacity={opacities.meso}
   181→          viewportBounds={viewportBounds}
   182→          spatialIndex={spatialIndex}
   183→          hoveredTaskId={hoveredTaskId}
   184→          selectedTaskId={selectedTaskId}
   185→          focusedTaskId={focusedTaskId}
   186→        />
   187→      )}
   188→      {opacities.micro > 0 && (
   189→        <MicroLayer
   190→          tasks={tasks}
   191→          trainCount={trainCount}
   192→          opacity={opacities.micro}
   193→          viewportBounds={viewportBounds}
   194→          hoveredTaskId={hoveredTaskId}
   195→          selectedTaskId={selectedTaskId}
   196→          focusedTaskId={focusedTaskId}
   197→        />
   198→      )}
   199→    </group>
   200→  );
   201→}
   202→
   203→/**
   204→ * Navigation target for programmatic navigation
   205→ * Can specify trainIndex, dayOffset, or both
   206→ */
   207→export interface NavigationTarget {
   208→  /** Train index (0-based) to center on vertically */
   209→  trainIndex?: number;
   210→  /** Day offset from start date to center on horizontally */
   211→  dayOffset?: number;
   212→  /** Optional zoom level to set (defaults to current zoom) */
   213→  zoom?: number;
   214→}
   215→
   216→interface InfiniteCanvasProps {
   217→  zoom: number;
   218→  lod: LODLevel;
   219→  onZoomChange: (zoom: number) => void;
   220→  /**
   221→   * Called when viewport position changes.
   222→   * @param viewport - Object with topY, leftX, rightX coordinates
   223→   */
   224→  onViewportChange?: (viewport: ViewportInfo) => void;
   225→  /**
   226→   * Called when the effective minimum zoom changes.
   227→   * Used by parent to enforce zoom limits on buttons.
   228→   */
   229→  onMinZoomChange?: (minZoom: number) => void;
   230→  /**
   231→   * Request a smooth animated zoom to target level.
   232→   * Called by parent buttons for +/- zoom with animation.
   233→   */
   234→  animatedZoomTarget?: number | null;
   235→  /**
   236→   * Called when animated zoom completes or is acknowledged.
   237→   */
   238→  onAnimatedZoomComplete?: () => void;
   239→  /**
   240→   * Request navigation to a specific train/date.
   241→   * Set to null after navigation completes.
   242→   */
   243→  navigationTarget?: NavigationTarget | null;
   244→  /**
   245→   * Called when navigation animation completes.
   246→   */
   247→  onNavigationComplete?: () => void;
   248→  /**
   249→   * Whether performance monitor panel is visible (PERF-001)
   250→   */
   251→  perfVisible?: boolean;
   252→  /**
   253→   * Current performance event type for logging context (PERF-001)
   254→   */
   255→  perfEvent?: PerfEvent;
   256→}
   257→
   258→// Navigation limits
   259→const ABSOLUTE_MIN_ZOOM = 0.05; // Absolute minimum to prevent extreme zoom out
   260→const MAX_ZOOM = 5.0;
   261→
   262→// Momentum physics constants
   263→const MOMENTUM_FRICTION = 0.93; // Per-frame velocity multiplier (0.93-0.95 recommended)
   264→const MOMENTUM_MIN_VELOCITY = 0.5; // Stop threshold in world units
   265→const MOMENTUM_VELOCITY_SAMPLES = 5; // Number of velocity samples to average
   266→
   267→// Smooth zoom constants
   268→const ZOOM_ANIMATION_DURATION = 250; // ms for animated zoom transitions
   269→// NOTE: ZOOM_ACCUMULATION_TIMEOUT (50ms) and PINCH_ZOOM_SENSITIVITY (0.01) removed as unused
   270→
   271→// Cross-platform scroll normalization constants (F121)
   272→// Based on Facebook's normalizeWheel pattern and UX_RESEARCH.md
   273→const LINE_HEIGHT = 40; // Pixels per line (for deltaMode === 1)
   274→const PAGE_HEIGHT = 800; // Pixels per page (for deltaMode === 2)
   275→const MOUSE_ZOOM_SENSITIVITY = 0.003; // Base zoom sensitivity for mouse wheel
   276→const TRACKPAD_ZOOM_SENSITIVITY = 0.001; // Lower sensitivity for trackpad (many small events)
   277→const MAX_ZOOM_DELTA_PER_EVENT = 0.5; // Cap zoom change per event to prevent jumps
   278→const TRACKPAD_DETECTION_THRESHOLD = 20; // ms - events faster than this are trackpad
   279→const TRACKPAD_EVENT_COUNT_THRESHOLD = 3; // Number of rapid events to confirm trackpad
   280→
   281→// Scroll modifier pan sensitivity (F016, F017)
   282→// Convert wheel delta (pixels) to camera pan (world units)
   283→const SCROLL_PAN_SENSITIVITY = 1.5;
   284→
   285→// Keyboard shortcuts constants (F027, F028)
   286→const KEYBOARD_ZOOM_STEP = 1.5; // Zoom multiplier per keypress (1.5x = 150%)
   287→const KEYBOARD_PAN_STEP = 100; // Pixels to pan per arrow key press (in world units)
   288→const KEYBOARD_PAGE_STEP = 500; // Pixels for Page Up/Down (in world units)
   289→
   290→const { pxPerDay, pxPerTrain } = DEFAULT_VIEW_CONFIG;
   291→
   292→/**
   293→ * Velocity sample for momentum calculation
   294→ * (Local type - only used for velocity tracking refs, not persisted state)
   295→ */
   296→interface VelocitySample {
   297→  x: number;
   298→  y: number;
   299→  time: number;
   300→}
   301→
   302→/**
   303→ * Local momentum animation state (includes animationId which is not in store)
   304→ * The actual momentum velocity is managed in canvasStore.viewport.momentum
   305→ */
   306→interface LocalMomentumState {
   307→  animationId: number | null;
   308→}
   309→
   310→/**
   311→ * Local zoom animation state (includes animationId)
   312→ * Animation parameters are stored in canvasStore.viewport.animation
   313→ */
   314→interface LocalZoomAnimationState {
   315→  animationId: number | null;
   316→}
   317→
   318→/**
   319→ * Pinch-to-zoom state for touch gestures
   320→ */
   321→interface PinchState {
   322→  active: boolean;
   323→  initialDistance: number;
   324→  initialZoom: number;
   325→  centerX: number;
   326→  centerY: number;
   327→  pointers: Map<number, { x: number; y: number }>;
   328→}
   329→
   330→/**
   331→ * Easing functions for smooth animations
   332→ * quadOut provides Google Maps-style smooth deceleration
   333→ */
   334→const Easing = {
   335→  quadOut: (t: number) => t * (2 - t),
   336→  cubicOut: (t: number) => 1 - Math.pow(1 - t, 3),
   337→};
   338→
   339→// Task block dimensions for hit testing (matching MesoLayer)
   340→const TASK_HEIGHT = pxPerTrain - 4;
   341→
   342→// ─────────────────────────────────────────────────────────────
   343→// KEYBOARD NAVIGATION HELPERS (F021)
   344→// ─────────────────────────────────────────────────────────────
   345→
   346→/**
   347→ * Get tasks visible within the current viewport
   348→ * Sorted by train index (Y) then start day (X) for logical tab order
   349→ */
   350→function getVisibleTasks(
   351→  tasks: ReturnType<typeof getRenderData>['tasks'],
   352→  viewportBounds: ViewportBounds
   353→): ReturnType<typeof getRenderData>['tasks'] {
   354→  const visibleTasks = tasks.filter((task) => {
   355→    const taskStartX = task.startDay * pxPerDay;
   356→    const taskEndX = taskStartX + task.duration * pxPerDay;
   357→    const taskY = -task.trainIndex * pxPerTrain - pxPerTrain / 2;
   358→
   359→    // Check if task overlaps with viewport
   360→    const xOverlap = taskEndX >= viewportBounds.minX && taskStartX <= viewportBounds.maxX;
   361→    const yOverlap = taskY >= viewportBounds.minY - pxPerTrain && taskY <= viewportBounds.maxY + pxPerTrain;
   362→
   363→    return xOverlap && yOverlap;
   364→  });
   365→
   366→  // Sort by train index (row), then by start day (column) for natural reading order
   367→  return visibleTasks.sort((a, b) => {
   368→    if (a.trainIndex !== b.trainIndex) {
   369→      return a.trainIndex - b.trainIndex;
   370→    }
   371→    return a.startDay - b.startDay;
   372→  });
   373→}
   374→
   375→/**
   376→ * Find next task in a specific direction from the current focused task
   377→ * Direction: 'left' | 'right' | 'up' | 'down'
   378→ */
   379→function findNextTaskInDirection(
   380→  tasks: ReturnType<typeof getRenderData>['tasks'],
   381→  currentTaskId: string,
   382→  direction: 'left' | 'right' | 'up' | 'down'
   383→): string | null {
   384→  const currentTask = tasks.find((t) => t.id === currentTaskId);
   385→  if (!currentTask) return null;
   386→
   387→  const currentX = currentTask.startDay * pxPerDay + (currentTask.duration * pxPerDay) / 2;
   388→  const currentY = -currentTask.trainIndex;
   389→
   390→  let bestMatch: typeof currentTask | null = null;
   391→  let bestScore = Infinity;
   392→
   393→  for (const task of tasks) {
   394→    if (task.id === currentTaskId) continue;
   395→
   396→    const taskX = task.startDay * pxPerDay + (task.duration * pxPerDay) / 2;
   397→    const taskY = -task.trainIndex;
   398→
   399→    let isInDirection = false;
   400→    let score = 0;
   401→
   402→    switch (direction) {
   403→      case 'left':
   404→        isInDirection = taskX < currentX;
   405→        if (isInDirection) {
   406→          // Prefer same row, then closest to the left
   407→          const rowPenalty = Math.abs(taskY - currentY) * 10000;
   408→          score = (currentX - taskX) + rowPenalty;
   409→        }
   410→        break;
   411→      case 'right':
   412→        isInDirection = taskX > currentX;
   413→        if (isInDirection) {
   414→          const rowPenalty = Math.abs(taskY - currentY) * 10000;
   415→          score = (taskX - currentX) + rowPenalty;
   416→        }
   417→        break;
   418→      case 'up':
   419→        isInDirection = taskY > currentY;
   420→        if (isInDirection) {
   421→          // Prefer closest row above with similar X
   422→          const xPenalty = Math.abs(taskX - currentX) / 100;
   423→          score = (taskY - currentY) + xPenalty;
   424→        }
   425→        break;
   426→      case 'down':
   427→        isInDirection = taskY < currentY;
   428→        if (isInDirection) {
   429→          const xPenalty = Math.abs(taskX - currentX) / 100;
   430→          score = (currentY - taskY) + xPenalty;
   431→        }
   432→        break;
   433→    }
   434→
   435→    if (isInDirection && score < bestScore) {
   436→      bestScore = score;
   437→      bestMatch = task;
   438→    }
   439→  }
   440→
   441→  return bestMatch?.id || null;
   442→}
   443→
   444→/**
   445→ * Find task at screen position (hit testing for hover/click)
   446→ *
   447→ * Converts screen coordinates to world coordinates and finds
   448→ * which task (if any) is under the cursor.
   449→ *
   450→ * @param screenX - Screen X coordinate (e.g., clientX)
   451→ * @param screenY - Screen Y coordinate (e.g., clientY)
   452→ * @param containerRect - Container element bounding rect
   453→ * @param cameraX - Camera X position in world coordinates
   454→ * @param cameraY - Camera Y position in world coordinates
   455→ * @param zoom - Current zoom level
   456→ * @param canvasWidth - Canvas width in pixels
   457→ * @param canvasHeight - Canvas height in pixels
   458→ * @param tasks - Array of tasks to test against
   459→ * @returns Task ID if found, null otherwise
   460→ */
   461→function findTaskAtPosition(
   462→  screenX: number,
   463→  screenY: number,
   464→  containerRect: DOMRect,
   465→  cameraX: number,
   466→  cameraY: number,
   467→  zoom: number,
   468→  canvasWidth: number,
   469→  canvasHeight: number,
   470→  tasks: ReturnType<typeof getRenderData>['tasks']
   471→): string | null {
   472→  // Convert screen coords to canvas coords (relative to container)
   473→  const canvasX = screenX - containerRect.left;
   474→  const canvasY = screenY - containerRect.top;
   475→
   476→  // Calculate half viewport in world units
   477→  const halfViewX = canvasWidth / 2 / zoom;
   478→  const halfViewY = canvasHeight / 2 / zoom;
   479→
   480→  // Convert canvas coords to world coords
   481→  // canvasX=0 is left edge of viewport, which is cameraX - halfViewX in world
   482→  // canvasY=0 is top edge of viewport, which is cameraY + halfViewY in world
   483→  const worldX = cameraX - halfViewX + (canvasX / zoom);
   484→  const worldY = cameraY + halfViewY - (canvasY / zoom);
   485→
   486→  // Find task at world position
   487→  for (const task of tasks) {
   488→    const taskStartX = task.startDay * pxPerDay;
   489→    const taskEndX = taskStartX + task.duration * pxPerDay;
   490→    const taskCenterY = -task.trainIndex * pxPerTrain - pxPerTrain / 2;
   491→    const taskTopY = taskCenterY + TASK_HEIGHT / 2;
   492→    const taskBottomY = taskCenterY - TASK_HEIGHT / 2;
   493→
   494→    if (
   495→      worldX >= taskStartX &&
   496→      worldX <= taskEndX &&
   497→      worldY <= taskTopY &&
   498→      worldY >= taskBottomY
   499→    ) {
   500→      return task.id;
   501→    }
   502→  }
   503→
   504→  return null;
   505→}
   506→
   507→/**
   508→ * Camera controller component (inside R3F context)
   509→ * Handles initial positioning and syncs camera with external state
   510→ *
   511→ * IMPORTANT: Uses R3F's `size` from useThree() which is the actual canvas size,
   512→ * not the container div size (which can differ due to flexbox/layout).
   513→ */
   514→function CameraController({
   515→  cameraX,
   516→  cameraY,
   517→  zoom,
   518→  worldBounds,
   519→  isInitialized,
   520→  onInitialized,
   521→  onViewportChange,
   522→}: {
   523→  cameraX: number;
   524→  cameraY: number;
   525→  zoom: number;
   526→  worldBounds: WorldBounds;
   527→  isInitialized: boolean;
   528→  onInitialized: (pos: { x: number; y: number }, size: { width: number; height: number }) => void;
   529→  onViewportChange?: (viewport: ViewportInfo) => void;
   530→}) {
   531→  const { camera, size } = useThree();
   532→
   533→  // Initialize camera position on first render using actual R3F size
   534→  useEffect(() => {
   535→    if (isInitialized || size.width === 0 || size.height === 0) return;
   536→
   537→    const halfViewX = size.width / 2 / zoom;
   538→    const halfViewY = size.height / 2 / zoom;
   539→
   540→    // Position camera to show top-left corner (X=0, Y=0)
   541→    const initialCameraX = halfViewX;
   542→    const initialCameraY = -halfViewY;
   543→
   544→    // Clamp to world bounds
   545→    const minCameraX = worldBounds.minX + halfViewX;
   546→    const maxCameraX = worldBounds.maxX - halfViewX;
   547→    const minCameraY = worldBounds.minY + halfViewY;
   548→    const maxCameraY = worldBounds.maxY - halfViewY;
   549→
   550→    const clampedX = Math.max(minCameraX, Math.min(maxCameraX, initialCameraX));
   551→    const clampedY = Math.max(minCameraY, Math.min(maxCameraY, initialCameraY));
   552→
   553→    // Update camera
   554→    camera.position.x = clampedX;
   555→    camera.position.y = clampedY;
   556→    (camera as any).zoom = zoom;
   557→    camera.updateProjectionMatrix();
   558→
   559→    // Notify parent of initial position and actual canvas size
   560→    onInitialized({ x: clampedX, y: clampedY }, { width: size.width, height: size.height });
   561→
   562→    // Notify viewport change with full viewport info
   563→    const topY = clampedY + halfViewY;
   564→    const leftX = clampedX - halfViewX;
   565→    const rightX = clampedX + halfViewX;
   566→    onViewportChange?.({ topY, leftX, rightX });
   567→  }, [size, zoom, worldBounds, camera, isInitialized, onInitialized, onViewportChange]);
   568→
   569→  // Sync camera with external state changes (after initialization)
   570→  useEffect(() => {
   571→    if (!isInitialized) return;
   572→
   573→    camera.position.x = cameraX;
   574→    camera.position.y = cameraY;
   575→    (camera as any).zoom = zoom;
   576→    camera.updateProjectionMatrix();
   577→  }, [camera, cameraX, cameraY, zoom, isInitialized]);
   578→
   579→  return null;
   580→}
   581→
   582→// ─────────────────────────────────────────────────────────────
   583→// ARIA LABELS FOR ACCESSIBILITY (F022)
   584→// ─────────────────────────────────────────────────────────────
   585→
   586→/**
   587→ * Human-readable LOD level names for screen reader announcements
   588→ */
   589→const LOD_LABELS: Record<LODLevel, string> = {
   590→  MACRO: 'Strategic view showing 10-year overview with heatmap',
   591→  MESO: 'Tactical view showing task blocks across trains',
   592→  MICRO: 'Detailed view showing individual task cards',
   593→};
   594→
   595→/**
   596→ * Format zoom level for screen reader announcement
   597→ */
   598→function formatZoomForAria(zoom: number): string {
   599→  const percentage = Math.round(zoom * 100);
   600→  return `${percentage} percent zoom`;
   601→}
   602→
   603→export function InfiniteCanvas({
   604→  zoom,
   605→  lod,
   606→  onZoomChange,
   607→  onViewportChange,
   608→  onMinZoomChange,
   609→  animatedZoomTarget,
   610→  onAnimatedZoomComplete,
   611→  navigationTarget,
   612→  onNavigationComplete,
   613→  perfVisible: _perfVisible = false,
   614→  perfEvent = 'idle',
   615→}: InfiniteCanvasProps) {
   616→  const containerRef = useRef<HTMLDivElement>(null);
   617→
   618→  // ─────────────────────────────────────────────────────────────
   619→  // ARIA LIVE REGION STATE (F022)
   620→  // ─────────────────────────────────────────────────────────────
   621→  const ariaLiveRef = useRef<HTMLDivElement>(null);
   622→  const previousLodRef = useRef<LODLevel>(lod);
   623→  const previousZoomRef = useRef<number>(zoom);
   624→  const zoomAnnouncementTimeoutRef = useRef<number | null>(null);
   625→
   626→  // ─────────────────────────────────────────────────────────────
   627→  // STATE FROM CANVAS MACHINE (replaces useState)
   628→  // Using useSyncExternalStore under the hood - no stale closures!
   629→  // ─────────────────────────────────────────────────────────────
   630→  const isInitialized = useCanvasSelector((s) => s.viewport.isInitialized);
   631→  const canvasSize = useCanvasSelector((s) => s.viewport.canvasSize);
   632→  const cameraPos = useCanvasSelector((s) => s.viewport.camera);
   633→  const isPanning = useCanvasSelector((s) => s.viewport.isPanning);
   634→  // Note: panStart, cameraPosAtPanStart, momentum are read from store directly in handlers for fresh values
   635→
   636→  // Interaction state (F018 hover, F019 selection)
   637→  const hoveredTaskId = useCanvasSelector((s) => s.interaction.hoveredTaskId);
   638→  const selectedTaskId = useCanvasSelector((s) => s.interaction.selectedTaskId);
   639→  const focusedTaskId = useCanvasSelector((s) => s.interaction.focusedTaskId);
   640→  const isHoverable = useCanvasSelector((s) => s.interaction.isHoverable);
   641→
   642→  // Get render data (memoized)
   643→  const { trains, tasks } = useMemo(() => getRenderData(), []);
   644→
   645→  // Build spatial index for viewport culling (PERF-002)
   646→  const spatialIndex = useSpatialIndex(tasks);
   647→
   648→  // Calculate world bounds (for pan clamping)
   649→  const worldBounds = useMemo<WorldBounds>(() => {
   650→    const totalDays = 365 * 10; // 10 years
   651→    return calculateWorldBounds(trains.length, totalDays);
   652→  }, [trains.length]);
   653→
   654→  /**
   655→   * Calculate dynamic MIN_ZOOM to prevent white space around content.
   656→   * MIN_ZOOM is set so the viewport never exceeds the world bounds.
   657→   */
   658→  const effectiveMinZoom = useMemo(() => {
   659→    if (canvasSize.width === 0 || canvasSize.height === 0) {
   660→      return ABSOLUTE_MIN_ZOOM;
   661→    }
   662→
   663→    const worldWidth = worldBounds.maxX - worldBounds.minX;
   664→    const worldHeight = Math.abs(worldBounds.maxY - worldBounds.minY);
   665→
   666→    // Calculate zoom levels where viewport equals world dimensions
   667→    // At zoom Z: viewportWidth = canvasSize.width / Z
   668→    // To fit world: canvasSize.width / Z = worldWidth → Z = canvasSize.width / worldWidth
   669→    const minZoomX = canvasSize.width / worldWidth;
   670→    const minZoomY = canvasSize.height / worldHeight;
   671→
   672→    // Use the maximum to ensure content fills viewport in both dimensions
   673→    const dynamicMin = Math.max(minZoomX, minZoomY);
   674→
   675→    // Clamp to absolute minimum (safety) and return
   676→    return Math.max(ABSOLUTE_MIN_ZOOM, dynamicMin);
   677→  }, [canvasSize.width, canvasSize.height, worldBounds]);
   678→
   679→  // Notify parent when effective min zoom changes
   680→  useEffect(() => {
   681→    onMinZoomChange?.(effectiveMinZoom);
   682→  }, [effectiveMinZoom, onMinZoomChange]);
   683→
   684→  // ─────────────────────────────────────────────────────────────
   685→  // ARIA ANNOUNCEMENTS (F022)
   686→  // ─────────────────────────────────────────────────────────────
   687→
   688→  /**
   689→   * Announce message to screen readers via ARIA live region
   690→   */
   691→  const announceToScreenReader = useCallback((message: string) => {
   692→    if (ariaLiveRef.current) {
   693→      // Clear and set to trigger announcement even for same message
   694→      ariaLiveRef.current.textContent = '';
   695→      // Use setTimeout to ensure the clear is processed first
   696→      setTimeout(() => {
   697→        if (ariaLiveRef.current) {
   698→          ariaLiveRef.current.textContent = message;
   699→        }
   700→      }, 50);
   701→    }
   702→  }, []);
   703→
   704→  // Announce LOD level changes
   705→  useEffect(() => {
   706→    if (lod !== previousLodRef.current) {
   707→      previousLodRef.current = lod;
   708→      announceToScreenReader(`View changed to ${LOD_LABELS[lod]}`);
   709→    }
   710→  }, [lod, announceToScreenReader]);
   711→
   712→  // Announce significant zoom changes (debounced to avoid spam)
   713→  useEffect(() => {
   714→    // Only announce if zoom changed significantly (>10%)
   715→    const zoomDiff = Math.abs(zoom - previousZoomRef.current) / previousZoomRef.current;
   716→    if (zoomDiff < 0.1) return;
   717→
   718→    // Clear previous timeout
   719→    if (zoomAnnouncementTimeoutRef.current) {
   720→      clearTimeout(zoomAnnouncementTimeoutRef.current);
   721→    }
   722→
   723→    // Debounce zoom announcements (wait 500ms after last change)
   724→    zoomAnnouncementTimeoutRef.current = window.setTimeout(() => {
   725→      previousZoomRef.current = zoom;
   726→      announceToScreenReader(formatZoomForAria(zoom));
   727→    }, 500);
   728→
   729→    return () => {
   730→      if (zoomAnnouncementTimeoutRef.current) {
   731→        clearTimeout(zoomAnnouncementTimeoutRef.current);
   732→      }
   733→    };
   734→  }, [zoom, announceToScreenReader]);
   735→
   736→  // ─────────────────────────────────────────────────────────────
   737→  // LOCAL REFS (animation frame IDs, velocity samples - not state)
   738→  // These are not state because they don't affect rendering
   739→  // ─────────────────────────────────────────────────────────────
   740→  const velocitySamplesRef = useRef<VelocitySample[]>([]);
   741→  const momentumAnimationRef = useRef<LocalMomentumState>({
   742→    animationId: null,
   743→  });
   744→  const lastPointerPosRef = useRef({ x: 0, y: 0, time: 0 });
   745→  // Track if pointer moved significantly (to distinguish click from pan)
   746→  const pointerMovedRef = useRef(false);
   747→  const pointerDownPosRef = useRef({ x: 0, y: 0 });
   748→
   749→  // Smooth zoom animation state - only the animationId is local
   750→  // Animation parameters are now in canvasStore.viewport.animation
   751→  const zoomAnimationRef = useRef<LocalZoomAnimationState>({
   752→    animationId: null,
   753→  });
   754→
   755→  // Wheel event accumulation for trackpad smooth zoom + input detection (F121)
   756→  const wheelAccumulatorRef = useRef({
   757→    delta: 0,
   758→    cursorX: 0,
   759→    cursorY: 0,
   760→    timeout: null as ReturnType<typeof setTimeout> | null,
   761→    // Trackpad detection state
   762→    lastEventTime: 0,
   763→    rapidEventCount: 0,
   764→    isTrackpad: false,
   765→  });
   766→
   767→  // Pinch-to-zoom state
   768→  const pinchRef = useRef<PinchState>({
   769→    active: false,
   770→    initialDistance: 0,
   771→    initialZoom: 1,
   772→    centerX: 0,
   773→    centerY: 0,
   774→    pointers: new Map(),
   775→  });
   776→
   777→  /**
   778→   * Update camera position in the canvas store
   779→   * Using external store means no stale closures - getState() always returns current value
   780→   */
   781→  const updateCameraPos = useCallback((pos: { x: number; y: number }) => {
   782→    canvasStore.dispatch(canvasActions.viewport.setCamera(pos));
   783→  }, []);
   784→
   785→  /**
   786→   * Called by CameraController when it initializes with actual R3F canvas size
   787→   */
   788→  const handleCameraInitialized = useCallback(
   789→    (pos: { x: number; y: number }, size: { width: number; height: number }) => {
   790→      canvasStore.dispatch(
   791→        canvasActions.viewport.initialize({ camera: pos, canvasSize: size })
   792→      );
   793→    },
   794→    []
   795→  );
   796→
   797→  /**
   798→   * Calculate and notify the viewport position (topY, leftX, rightX)
   799→   */
   800→  const notifyViewportChange = useCallback(
   801→    (camX: number, camY: number, currentZoom: number) => {
   802→      const halfViewX = canvasSize.width / 2 / currentZoom;
   803→      const halfViewY = canvasSize.height / 2 / currentZoom;
   804→      const topY = camY + halfViewY;
   805→      const leftX = camX - halfViewX;
   806→      const rightX = camX + halfViewX;
   807→      onViewportChange?.({ topY, leftX, rightX });
   808→    },
   809→    [canvasSize.width, canvasSize.height, onViewportChange]
   810→  );
   811→
   812→  /**
   813→   * Calculate viewport bounds for frustum culling
   814→   * This determines which tasks are visible and need to be rendered
   815→   * IMPORTANT: Must be defined before handleKeyDown which uses it for F021
   816→   */
   817→  const viewportBounds = useMemo<ViewportBounds>(() => {
   818→    const halfViewX = canvasSize.width / 2 / zoom;
   819→    const halfViewY = canvasSize.height / 2 / zoom;
   820→
   821→    return {
   822→      minX: cameraPos.x - halfViewX,
   823→      maxX: cameraPos.x + halfViewX,
   824→      minY: cameraPos.y - halfViewY,
   825→      maxY: cameraPos.y + halfViewY,
   826→    };
   827→  }, [cameraPos.x, cameraPos.y, canvasSize.width, canvasSize.height, zoom]);
   828→
   829→  /**
   830→   * Clamp camera position to world bounds
   831→   */
   832→  const clampCameraToWorld = useCallback(
   833→    (x: number, y: number, currentZoom: number): { x: number; y: number } => {
   834→      const halfViewX = canvasSize.width / 2 / currentZoom;
   835→      const halfViewY = canvasSize.height / 2 / currentZoom;
   836→
   837→      const minCameraX = worldBounds.minX + halfViewX;
   838→      const maxCameraX = worldBounds.maxX - halfViewX;
   839→      const minCameraY = worldBounds.minY + halfViewY;
   840→      const maxCameraY = worldBounds.maxY - halfViewY;
   841→
   842→      const clampedX =
   843→        maxCameraX < minCameraX
   844→          ? (worldBounds.minX + worldBounds.maxX) / 2
   845→          : Math.max(minCameraX, Math.min(maxCameraX, x));
   846→
   847→      const clampedY =
   848→        maxCameraY < minCameraY
   849→          ? (worldBounds.minY + worldBounds.maxY) / 2
   850→          : Math.max(minCameraY, Math.min(maxCameraY, y));
   851→
   852→      return { x: clampedX, y: clampedY };
   853→    },
   854→    [canvasSize, worldBounds]
   855→  );
   856→
   857→  /**
   858→   * Stop any active momentum animation
   859→   */
   860→  const stopMomentum = useCallback(() => {
   861→    if (momentumAnimationRef.current.animationId) {
   862→      cancelAnimationFrame(momentumAnimationRef.current.animationId);
   863→      momentumAnimationRef.current.animationId = null;
   864→    }
   865→    // TECH-DEBT-002: @zazcart/tools action creators expect payload even when reducer doesn't need one
   866→    canvasStore.dispatch((canvasActions.viewport.stopMomentum as any)());
   867→    velocitySamplesRef.current = [];
   868→  }, []);
   869→
   870→  /**
   871→   * Stop any active zoom animation
   872→   */
   873→  const stopZoomAnimation = useCallback(() => {
   874→    if (zoomAnimationRef.current.animationId) {
   875→      cancelAnimationFrame(zoomAnimationRef.current.animationId);
   876→      zoomAnimationRef.current.animationId = null;
   877→    }
   878→    // Clear wheel accumulator
   879→    if (wheelAccumulatorRef.current.timeout) {
   880→      clearTimeout(wheelAccumulatorRef.current.timeout);
   881→      wheelAccumulatorRef.current.timeout = null;
   882→    }
   883→    wheelAccumulatorRef.current.delta = 0;
   884→  }, []);
   885→
   886→  /**
   887→   * Animate zoom smoothly from current to target
   888→   * Uses quadratic easing for Google Maps-like feel
   889→   *
   890→   * Now uses canvasStore for animation state - no stale closures in the animation loop
   891→   */
   892→  const animateZoomTo = useCallback(
   893→    (
   894→      targetZoom: number,
   895→      targetCameraX: number,
   896→      targetCameraY: number,
   897→      duration: number = ZOOM_ANIMATION_DURATION
   898→    ) => {
   899→      // Stop any existing animation
   900→      stopZoomAnimation();
   901→
   902→      // Get current state from store (always fresh)
   903→      const currentState = canvasStore.getState();
   904→      const currentCamera = currentState.viewport.camera;
   905→
   906→      // Start animation in store
   907→      canvasStore.dispatch(
   908→        canvasActions.viewport.startAnimation({
   909→          startX: currentCamera.x,
   910→          startY: currentCamera.y,
   911→          startZoom: zoom,
   912→          targetX: targetCameraX,
   913→          targetY: targetCameraY,
   914→          targetZoom: targetZoom,
   915→          duration: duration,
   916→        })
   917→      );
   918→
   919→      const animate = () => {
   920→        // Read animation state from store (always current, no stale closures)
   921→        const state = canvasStore.getState();
   922→        const anim = state.viewport.animation;
   923→
   924→        if (!anim.isAnimating) {
   925→          zoomAnimationRef.current.animationId = null;
   926→          return;
   927→        }
   928→
   929→        const elapsed = Date.now() - anim.startTime;
   930→        const progress = Math.min(elapsed / anim.duration, 1);
   931→        const easedProgress = Easing.quadOut(progress);
   932→
   933→        const currentZoom = anim.startZoom + (anim.targetZoom - anim.startZoom) * easedProgress;
   934→        const currentCameraX = anim.startX + (anim.targetX - anim.startX) * easedProgress;
   935→        const currentCameraY = anim.startY + (anim.targetY - anim.startY) * easedProgress;
   936→
   937→        // Clamp camera position
   938→        const clamped = clampCameraToWorld(currentCameraX, currentCameraY, currentZoom);
   939→
   940→        // Update store with new camera position
   941→        canvasStore.dispatch(
   942→          canvasActions.viewport.updateAnimation({ camera: clamped })
   943→        );
   944→        onZoomChange(currentZoom);
   945→        notifyViewportChange(clamped.x, clamped.y, currentZoom);
   946→
   947→        if (progress < 1) {
   948→          zoomAnimationRef.current.animationId = requestAnimationFrame(animate);
   949→        } else {
   950→          // TECH-DEBT-002: @zazcart/tools action creators expect payload even when reducer doesn't need one
   951→          canvasStore.dispatch((canvasActions.viewport.stopAnimation as any)());
   952→          zoomAnimationRef.current.animationId = null;
   953→        }
   954→      };
   955→
   956→      zoomAnimationRef.current.animationId = requestAnimationFrame(animate);
   957→    },
   958→    [zoom, clampCameraToWorld, onZoomChange, notifyViewportChange, stopZoomAnimation]
   959→  );
   960→
   961→  /**
   962→   * Calculate average velocity from samples
   963→   * Samples contain individual deltas (movement per event), not absolute positions
   964→   */
   965→  const calculateAverageVelocity = useCallback(() => {
   966→    const samples = velocitySamplesRef.current;
   967→    if (samples.length < 2) return { vx: 0, vy: 0 };
   968→
   969→    // Use only recent samples (last N samples)
   970→    const recentSamples = samples.slice(-MOMENTUM_VELOCITY_SAMPLES);
   971→    if (recentSamples.length < 2) return { vx: 0, vy: 0 };
   972→
   973→    // Calculate total displacement and time
   974→    const first = recentSamples[0];
   975→    const last = recentSamples[recentSamples.length - 1];
   976→    const dt = last.time - first.time;
   977→
   978→    if (dt <= 0) return { vx: 0, vy: 0 };
   979→
   980→    // Sum all deltas to get total displacement
   981→    let totalDx = 0;
   982→    let totalDy = 0;
   983→    for (const sample of recentSamples) {
   984→      totalDx += sample.x;
   985→      totalDy += sample.y;
   986→    }
   987→
   988→    // Velocity in world units per millisecond
   989→    const vx = totalDx / dt;
   990→    const vy = totalDy / dt;
   991→
   992→    return { vx, vy };
   993→  }, []);
   994→
   995→  /**
   996→   * Start momentum animation after drag release
   997→   *
   998→   * Now uses canvasStore for momentum state - no stale closures in the animation loop
   999→   */
  1000→  const startMomentum = useCallback(
  1001→    (vx: number, vy: number) => {
  1002→      // Convert velocity from world/ms to world/frame (at 60fps, ~16.67ms per frame)
  1003→      const frameTime = 16.67;
  1004→      const velocityX = vx * frameTime;
  1005→      const velocityY = vy * frameTime;
  1006→
  1007→      // Start momentum in store
  1008→      canvasStore.dispatch(
  1009→        canvasActions.viewport.startMomentum({ velocityX, velocityY })
