  1542→        cancelAnimationFrame(zoomAnimationRef.current.animationId);
  1543→      }
  1544→      if (wheelAccumulatorRef.current.timeout) {
  1545→        clearTimeout(wheelAccumulatorRef.current.timeout);
  1546→      }
  1547→    };
  1548→  }, []);
  1549→
  1550→  // Handle animated zoom requests from parent (button +/-)
  1551→  useEffect(() => {
  1552→    if (animatedZoomTarget == null || !isInitialized) return;
  1553→
  1554→    // Calculate new camera position (zoom toward center of viewport)
  1555→    const targetZoom = Math.max(effectiveMinZoom, Math.min(MAX_ZOOM, animatedZoomTarget));
  1556→    if (Math.abs(targetZoom - zoom) < 0.001) {
  1557→      onAnimatedZoomComplete?.();
  1558→      return;
  1559→    }
  1560→
  1561→    // Zoom toward center (no cursor offset)
  1562→    const clamped = clampCameraToWorld(cameraPos.x, cameraPos.y, targetZoom);
  1563→    animateZoomTo(targetZoom, clamped.x, clamped.y, ZOOM_ANIMATION_DURATION);
  1564→
  1565→    // Acknowledge the request
  1566→    onAnimatedZoomComplete?.();
  1567→  }, [animatedZoomTarget, isInitialized, zoom, effectiveMinZoom, cameraPos, clampCameraToWorld, animateZoomTo, onAnimatedZoomComplete]);
  1568→
  1569→  // Handle navigation requests from parent (F124: sidebar/timeline navigation)
  1570→  useEffect(() => {
  1571→    if (navigationTarget == null || !isInitialized) return;
  1572→
  1573→    // Stop any active animations
  1574→    stopMomentum();
  1575→    stopZoomAnimation();
  1576→
  1577→    // Calculate target camera position from trainIndex and/or dayOffset
  1578→    // trainIndex → Y position: trainIndex * pxPerTrain (negative because Y goes down)
  1579→    // dayOffset → X position: dayOffset * pxPerDay
  1580→    let targetCameraX = cameraPos.x;
  1581→    let targetCameraY = cameraPos.y;
  1582→    const targetZoom = navigationTarget.zoom != null
  1583→      ? Math.max(effectiveMinZoom, Math.min(MAX_ZOOM, navigationTarget.zoom))
  1584→      : zoom;
  1585→
  1586→    if (navigationTarget.trainIndex != null) {
  1587→      // Center on the train row
  1588→      // Camera Y should be positioned so the train is in the center of viewport
  1589→      // Train position in world: -trainIndex * pxPerTrain - pxPerTrain / 2
  1590→      targetCameraY = -navigationTarget.trainIndex * pxPerTrain - pxPerTrain / 2;
  1591→    }
  1592→
  1593→    if (navigationTarget.dayOffset != null) {
  1594→      // Center on the date
  1595→      // Day position in world: dayOffset * pxPerDay
  1596→      targetCameraX = navigationTarget.dayOffset * pxPerDay;
  1597→    }
  1598→
  1599→    // Clamp to world bounds
  1600→    const clamped = clampCameraToWorld(targetCameraX, targetCameraY, targetZoom);
  1601→
  1602→    // Animate to target position
  1603→    animateZoomTo(targetZoom, clamped.x, clamped.y, 350); // 350ms for navigation
  1604→
  1605→    // Acknowledge the request
  1606→    onNavigationComplete?.();
  1607→  }, [navigationTarget, isInitialized, zoom, effectiveMinZoom, cameraPos, clampCameraToWorld, animateZoomTo, stopMomentum, stopZoomAnimation, onNavigationComplete]);
  1608→
  1609→  /**
  1610→   * Handle pan start / pinch start
  1611→   *
  1612→   * Now uses canvasStore to get camera position - no stale closures
  1613→   */
  1614→  const handlePointerDown = useCallback(
  1615→    (e: React.PointerEvent) => {
  1616→      if (!isInitialized) return;
  1617→
  1618→      const pinch = pinchRef.current;
  1619→
  1620→      // Track pointer for pinch detection
  1621→      pinch.pointers.set(e.pointerId, { x: e.clientX, y: e.clientY });
  1622→
  1623→      // Check for pinch gesture (2 pointers)
  1624→      if (pinch.pointers.size === 2) {
  1625→        // Stop pan and momentum when pinch starts
  1626→        stopMomentum();
  1627→        stopZoomAnimation();
  1628→        // TECH-DEBT-002: @zazcart/tools action creators expect payload even when reducer doesn't need one
  1629→        canvasStore.dispatch((canvasActions.viewport.endPan as any)());
  1630→
  1631→        const pointers = Array.from(pinch.pointers.values());
  1632→        const dx = pointers[0].x - pointers[1].x;
  1633→        const dy = pointers[0].y - pointers[1].y;
  1634→        pinch.initialDistance = Math.sqrt(dx * dx + dy * dy);
  1635→        pinch.initialZoom = zoom;
  1636→        // Get camera position from store (always current, no stale closures)
  1637→        const currentCamera = canvasStore.getState().viewport.camera;
  1638→        pinch.centerX = currentCamera.x;
  1639→        pinch.centerY = currentCamera.y;
  1640→        pinch.active = true;
  1641→        return;
  1642→      }
  1643→
  1644→      // Single pointer = pan
  1645→      if (pinch.pointers.size === 1) {
  1646→        // Stop any active momentum and zoom animation
  1647→        stopMomentum();
  1648→        stopZoomAnimation();
  1649→
  1650→        // Get camera position from store (always current, no stale closures)
  1651→        const currentCamera = canvasStore.getState().viewport.camera;
  1652→
  1653→        // Track pointer down position for click detection (F019)
  1654→        pointerDownPosRef.current = { x: e.clientX, y: e.clientY };
  1655→        pointerMovedRef.current = false;
  1656→
  1657→        // Start pan in store
  1658→        canvasStore.dispatch(
  1659→          canvasActions.viewport.startPan({
  1660→            panStart: { x: e.clientX, y: e.clientY },
  1661→            cameraPosAtPanStart: currentCamera,
  1662→          })
  1663→        );
  1664→
  1665→        // Initialize velocity tracking
  1666→        const now = performance.now();
  1667→        lastPointerPosRef.current = { x: e.clientX, y: e.clientY, time: now };
  1668→        velocitySamplesRef.current = [];
  1669→      }
  1670→
  1671→      (e.target as HTMLElement).setPointerCapture(e.pointerId);
  1672→    },
  1673→    [zoom, isInitialized, stopMomentum, stopZoomAnimation]
  1674→  );
  1675→
  1676→  /**
  1677→   * Handle hover detection (F018)
  1678→   * Updates hovered task based on mouse position
  1679→   */
  1680→  const updateHover = useCallback(
  1681→    (e: React.PointerEvent) => {
  1682→      // Only update hover when not panning (avoid expensive calculations during drag)
  1683→      const state = canvasStore.getState();
  1684→      if (state.viewport.isPanning) {
  1685→        // Clear hover during panning
  1686→        if (state.interaction.hoveredTaskId !== null) {
  1687→          canvasStore.dispatch(canvasActions.interaction.setHoveredTask(null));
  1688→        }
  1689→        return;
  1690→      }
  1691→
  1692→      // Get container rect for coordinate conversion
  1693→      const container = containerRef.current;
  1694→      if (!container) return;
  1695→
  1696→      const rect = container.getBoundingClientRect();
  1697→      const camera = state.viewport.camera;
  1698→
  1699→      // Find task under cursor
  1700→      const taskId = findTaskAtPosition(
  1701→        e.clientX,
  1702→        e.clientY,
  1703→        rect,
  1704→        camera.x,
  1705→        camera.y,
  1706→        zoom,
  1707→        canvasSize.width,
  1708→        canvasSize.height,
  1709→        tasks
  1710→      );
  1711→
  1712→      // Only update if changed (avoid unnecessary state updates)
  1713→      if (taskId !== state.interaction.hoveredTaskId) {
  1714→        canvasStore.dispatch(canvasActions.interaction.setHoveredTask(taskId));
  1715→      }
  1716→    },
  1717→    [zoom, canvasSize, tasks]
  1718→  );
  1719→
  1720→  /**
  1721→   * Handle pan move / pinch move
  1722→   *
  1723→   * Now uses canvasStore for pan state - values always current
  1724→   */
  1725→  const handlePointerMove = useCallback(
  1726→    (e: React.PointerEvent) => {
  1727→      const pinch = pinchRef.current;
  1728→
  1729→      // Update pointer position
  1730→      if (pinch.pointers.has(e.pointerId)) {
  1731→        pinch.pointers.set(e.pointerId, { x: e.clientX, y: e.clientY });
  1732→      }
  1733→
  1734→      // Handle pinch gesture
  1735→      if (pinch.active && pinch.pointers.size === 2) {
  1736→        const pointers = Array.from(pinch.pointers.values());
  1737→        const dx = pointers[0].x - pointers[1].x;
  1738→        const dy = pointers[0].y - pointers[1].y;
  1739→        const currentDistance = Math.sqrt(dx * dx + dy * dy);
  1740→
  1741→        if (pinch.initialDistance > 0) {
  1742→          const scale = currentDistance / pinch.initialDistance;
  1743→          const centerX = (pointers[0].x + pointers[1].x) / 2;
  1744→          const centerY = (pointers[0].y + pointers[1].y) / 2;
  1745→          handlePinchZoom(scale, centerX, centerY);
  1746→        }
  1747→        return;
  1748→      }
  1749→
  1750→      // Update hover state (F018) - always run to update cursor
  1751→      updateHover(e);
  1752→
  1753→      // Handle pan - get current state from store
  1754→      const state = canvasStore.getState();
  1755→      if (!state.viewport.isPanning) return;
  1756→
  1757→      const dx = (e.clientX - state.viewport.panStart.x) / zoom;
  1758→      const dy = (e.clientY - state.viewport.panStart.y) / zoom;
  1759→
  1760→      // Detect significant movement (F019: to distinguish click from pan)
  1761→      // Using 8px threshold - movement greater than this is a pan, not a click
  1762→      // Higher threshold helps with touchpad/mouse precision issues
  1763→      const moveX = e.clientX - pointerDownPosRef.current.x;
  1764→      const moveY = e.clientY - pointerDownPosRef.current.y;
  1765→      const moveDistance = Math.sqrt(moveX * moveX + moveY * moveY);
  1766→      if (moveDistance > 8) {
  1767→        pointerMovedRef.current = true;
  1768→      }
  1769→
  1770→      const newX = state.viewport.cameraPosAtPanStart.x - dx;
  1771→      const newY = state.viewport.cameraPosAtPanStart.y + dy;
  1772→
  1773→      const clamped = clampCameraToWorld(newX, newY, zoom);
  1774→
  1775→      // Update pan in store
  1776→      canvasStore.dispatch(canvasActions.viewport.updatePan({ camera: clamped }));
  1777→      notifyViewportChange(clamped.x, clamped.y, zoom);
  1778→
  1779→      // Track velocity samples for momentum
  1780→      const now = performance.now();
  1781→      const worldDx = (e.clientX - lastPointerPosRef.current.x) / zoom;
  1782→      const worldDy = (e.clientY - lastPointerPosRef.current.y) / zoom;
  1783→
  1784→      velocitySamplesRef.current.push({
  1785→        x: worldDx,
  1786→        y: worldDy,
  1787→        time: now,
  1788→      });
  1789→
  1790→      // Keep only recent samples
  1791→      if (velocitySamplesRef.current.length > MOMENTUM_VELOCITY_SAMPLES * 2) {
  1792→        velocitySamplesRef.current = velocitySamplesRef.current.slice(-MOMENTUM_VELOCITY_SAMPLES);
  1793→      }
  1794→
  1795→      lastPointerPosRef.current = { x: e.clientX, y: e.clientY, time: now };
  1796→    },
  1797→    [zoom, clampCameraToWorld, notifyViewportChange, handlePinchZoom, updateHover]
  1798→  );
  1799→
  1800→  /**
  1801→   * Handle pan end / pinch end
  1802→   *
  1803→   * Now uses canvasStore for pan state
  1804→   */
  1805→  const handlePointerUp = useCallback(
  1806→    (e: React.PointerEvent) => {
  1807→      const pinch = pinchRef.current;
  1808→
  1809→      // Remove pointer from tracking
  1810→      pinch.pointers.delete(e.pointerId);
  1811→
  1812→      // Release pointer capture
  1813→      try {
  1814→        (e.target as HTMLElement).releasePointerCapture(e.pointerId);
  1815→      } catch {
  1816→        // Ignore if capture was already released
  1817→      }
  1818→
  1819→      // Reset pinch state when all pointers released
  1820→      if (pinch.pointers.size < 2) {
  1821→        pinch.active = false;
  1822→        pinch.initialDistance = 0;
  1823→      }
  1824→
  1825→      // Handle pan end with momentum - check store for isPanning
  1826→      const state = canvasStore.getState();
  1827→      if (state.viewport.isPanning && pinch.pointers.size === 0) {
  1828→        // TECH-DEBT-002: @zazcart/tools action creators expect payload even when reducer doesn't need one
  1829→        canvasStore.dispatch((canvasActions.viewport.endPan as any)());
  1830→
  1831→        // BUG-008: Momentum disabled - was causing elastic/jumping behavior
  1832→        // The momentum animation had stale closure issues despite the cameraPosRef fix
  1833→        // TODO: Reimplement with proper state synchronization if momentum UX is desired
  1834→        // Original code:
  1835→        // const { vx, vy } = calculateAverageVelocity();
  1836→        // const speed = Math.sqrt(vx ** 2 + vy ** 2);
  1837→        // if (speed > 0.01) { startMomentum(vx, vy); }
  1838→      }
  1839→    },
  1840→    [calculateAverageVelocity, startMomentum]
  1841→  );
  1842→
  1843→  /**
  1844→   * Handle double-click to zoom in at click location
  1845→   * Zooms 2x toward the clicked point with smooth animation
  1846→   *
  1847→   * Now uses animateZoomTo which uses the canvasStore
  1848→   */
  1849→  const handleDoubleClick = useCallback(
  1850→    (e: React.MouseEvent) => {
  1851→      if (!isInitialized) return;
  1852→
  1853→      // Stop any active animations
  1854→      stopMomentum();
  1855→      stopZoomAnimation();
  1856→
  1857→      const rect = containerRef.current?.getBoundingClientRect();
  1858→      if (!rect) return;
  1859→
  1860→      // Get current camera from store
  1861→      const currentCamera = canvasStore.getState().viewport.camera;
  1862→
  1863→      // Calculate target zoom (2x, clamped to MAX_ZOOM)
  1864→      const targetZoom = Math.min(zoom * 2, MAX_ZOOM);
  1865→      if (Math.abs(targetZoom - zoom) < 0.001) return;
  1866→
  1867→      // Cursor position relative to canvas center
  1868→      const cursorX = e.clientX - rect.left - rect.width / 2;
  1869→      const cursorY = e.clientY - rect.top - rect.height / 2;
  1870→
  1871→      // Calculate target camera position (zoom toward click point)
  1872→      const worldX = cursorX / zoom + currentCamera.x;
  1873→      const worldY = -cursorY / zoom + currentCamera.y;
  1874→      const newCameraX = worldX - cursorX / targetZoom;
  1875→      const newCameraY = worldY + cursorY / targetZoom;
  1876→
  1877→      const clamped = clampCameraToWorld(newCameraX, newCameraY, targetZoom);
  1878→
  1879→      // Animate with slightly longer duration for double-click (350ms)
  1880→      animateZoomTo(targetZoom, clamped.x, clamped.y, 350);
  1881→    },
  1882→    [zoom, isInitialized, stopMomentum, stopZoomAnimation, clampCameraToWorld, animateZoomTo]
  1883→  );
  1884→
  1885→  /**
  1886→   * Handle click to select/deselect task (F019)
  1887→   * Clicks on tasks select them, clicks on background deselect
  1888→   */
  1889→  const handleClick = useCallback(
  1890→    (e: React.MouseEvent) => {
  1891→      if (!isInitialized) return;
  1892→
  1893→      // Don't process clicks that are part of a pan gesture
  1894→      // If pointer moved significantly between down and up, this is a pan, not a click
  1895→      if (pointerMovedRef.current) {
  1896→        return;
  1897→      }
  1898→
  1899→      const state = canvasStore.getState();
  1900→
  1901→      const container = containerRef.current;
  1902→      if (!container) return;
  1903→
  1904→      const rect = container.getBoundingClientRect();
  1905→      const camera = state.viewport.camera;
  1906→
  1907→      // Find task at click position
  1908→      const taskId = findTaskAtPosition(
  1909→        e.clientX,
  1910→        e.clientY,
  1911→        rect,
  1912→        camera.x,
  1913→        camera.y,
  1914→        zoom,
  1915→        canvasSize.width,
  1916→        canvasSize.height,
  1917→        tasks
  1918→      );
  1919→
  1920→      if (taskId) {
  1921→        // Toggle selection: if clicking same task, deselect; otherwise, select
  1922→        if (taskId === state.interaction.selectedTaskId) {
  1923→          // TECH-DEBT-002: @zazcart/tools action creators expect payload even when reducer doesn't need one
  1924→          canvasStore.dispatch((canvasActions.interaction.clearSelection as any)());
  1925→        } else {
  1926→          canvasStore.dispatch(canvasActions.interaction.setSelectedTask(taskId));
  1927→        }
  1928→      } else {
  1929→        // Clicked on background: clear selection
  1930→        if (state.interaction.selectedTaskId !== null) {
  1931→          // TECH-DEBT-002: @zazcart/tools action creators expect payload even when reducer doesn't need one
  1932→          canvasStore.dispatch((canvasActions.interaction.clearSelection as any)());
  1933→        }
  1934→      }
  1935→    },
  1936→    [isInitialized, zoom, canvasSize, tasks]
  1937→  );
  1938→
  1939→  /**
  1940→   * Handle pointer leave - clear pan and hover state
  1941→   */
  1942→  const handlePointerLeave = useCallback(
  1943→    (e: React.PointerEvent) => {
  1944→      // Handle pan end
  1945→      handlePointerUp(e);
  1946→      // Clear hover state (F018)
  1947→      // TECH-DEBT-002: @zazcart/tools action creators expect payload even when reducer doesn't need one
  1948→      canvasStore.dispatch((canvasActions.interaction.clearHover as any)());
  1949→    },
  1950→    [handlePointerUp]
  1951→  );
  1952→
  1953→  // Determine cursor style: grabbing when panning, pointer when hovering task, grab otherwise
  1954→  const cursorStyle = isPanning ? 'grabbing' : isHoverable ? 'pointer' : 'grab';
  1955→
  1956→  // Generate aria-label with current state information (F022)
  1957→  const ariaLabel = `Metro maintenance planning canvas. ${LOD_LABELS[lod]}. ${formatZoomForAria(zoom)}. Use Tab to navigate tasks, Enter to select, Arrow keys to pan, plus minus to zoom.`;
  1958→
  1959→  return (
  1960→    <div
  1961→      ref={containerRef}
  1962→      // F022: ARIA attributes for accessibility
  1963→      role="application"
  1964→      aria-label={ariaLabel}
  1965→      aria-roledescription="Interactive maintenance scheduling canvas"
  1966→      style={{
  1967→        width: '100%',
  1968→        height: '100%',
  1969→        cursor: cursorStyle,
  1970→        touchAction: 'none',
  1971→        position: 'relative', // For absolute positioning of live region
  1972→      }}
  1973→      onPointerDown={handlePointerDown}
  1974→      onPointerMove={handlePointerMove}
  1975→      onPointerUp={handlePointerUp}
  1976→      onPointerLeave={handlePointerLeave}
  1977→      onDoubleClick={handleDoubleClick}
  1978→      onClick={handleClick}
  1979→    >
  1980→      {/* F022: ARIA Live Region for screen reader announcements */}
  1981→      <div
  1982→        ref={ariaLiveRef}
  1983→        role="status"
  1984→        aria-live="polite"
  1985→        aria-atomic="true"
  1986→        style={{
  1987→          position: 'absolute',
  1988→          width: '1px',
  1989→          height: '1px',
  1990→          padding: '0',
  1991→          margin: '-1px',
  1992→          overflow: 'hidden',
  1993→          clip: 'rect(0, 0, 0, 0)',
  1994→          whiteSpace: 'nowrap',
  1995→          border: '0',
  1996→        }}
  1997→      />
  1998→      <Canvas
  1999→        gl={{ antialias: true, alpha: false }}
  2000→        style={{ background: '#f4f4f5' }}
  2001→        orthographic
  2002→        camera={{
  2003→          position: [cameraPos.x, cameraPos.y, 100],
  2004→          zoom: zoom,
  2005→          near: 0.1,
  2006→          far: 1000,
  2007→        }}
  2008→      >
  2009→        <CameraController
  2010→          cameraX={cameraPos.x}
  2011→          cameraY={cameraPos.y}
  2012→          zoom={zoom}
  2013→          worldBounds={worldBounds}
  2014→          isInitialized={isInitialized}
  2015→          onInitialized={handleCameraInitialized}
  2016→          onViewportChange={onViewportChange}
  2017→        />
  2018→
  2019→        <color attach="background" args={['#f4f4f5']} />
  2020→
  2021→        {/* LOD-based layer rendering with smooth transitions */}
  2022→        <LODLayers
  2023→          tasks={tasks}
  2024→          trainCount={trains.length}
  2025→          zoom={zoom}
  2026→          viewportBounds={viewportBounds}
  2027→          spatialIndex={spatialIndex}
  2028→          hoveredTaskId={hoveredTaskId}
  2029→          selectedTaskId={selectedTaskId}
  2030→          focusedTaskId={focusedTaskId}
  2031→        />
  2032→
  2033→        {/* Performance monitor (PERF-001) */}
  2034→        {/* r3f-perf disabled due to troika compatibility issue - using stats.js PerformancePanel instead */}
  2035→        <PerfMonitor visible={false} currentEvent={perfEvent} />
  2036→      </Canvas>
  2037→    </div>
  2038→  );
  2039→}
