          if (nextTaskId) {
            canvasStore.dispatch(canvasActions.interaction.setFocusedTask(nextTaskId));
          }
        } else {
          // F028: Pan left
          stopMomentum();
          const newX = currentCamera.x - panStep;
          const clamped = clampCameraToWorld(newX, currentCamera.y, zoom);
          updateCameraPos(clamped);
          notifyViewportChange(clamped.x, clamped.y, zoom);
        }
        return;
      }

      if (e.key === 'ArrowRight') {
        e.preventDefault();
        // F021: If task focused, navigate to task on right
        if (currentFocusedTaskId) {
          const nextTaskId = findNextTaskInDirection(tasks, currentFocusedTaskId, 'right');
          if (nextTaskId) {
            canvasStore.dispatch(canvasActions.interaction.setFocusedTask(nextTaskId));
          }
        } else {
          // F028: Pan right
          stopMomentum();
          const newX = currentCamera.x + panStep;
          const clamped = clampCameraToWorld(newX, currentCamera.y, zoom);
          updateCameraPos(clamped);
          notifyViewportChange(clamped.x, clamped.y, zoom);
        }
        return;
      }

      if (e.key === 'ArrowUp') {
        e.preventDefault();
        // F021: If task focused, navigate to task above
        if (currentFocusedTaskId) {
          const nextTaskId = findNextTaskInDirection(tasks, currentFocusedTaskId, 'up');
          if (nextTaskId) {
            canvasStore.dispatch(canvasActions.interaction.setFocusedTask(nextTaskId));
          }
        } else {
          // F028: Pan up
          stopMomentum();
          const newY = currentCamera.y + panStep;
          const clamped = clampCameraToWorld(currentCamera.x, newY, zoom);
          updateCameraPos(clamped);
          notifyViewportChange(clamped.x, clamped.y, zoom);
        }
        return;
      }

      if (e.key === 'ArrowDown') {
        e.preventDefault();
        // F021: If task focused, navigate to task below
        if (currentFocusedTaskId) {
          const nextTaskId = findNextTaskInDirection(tasks, currentFocusedTaskId, 'down');
          if (nextTaskId) {
            canvasStore.dispatch(canvasActions.interaction.setFocusedTask(nextTaskId));
          }
        } else {
          // F028: Pan down
          stopMomentum();
          const newY = currentCamera.y - panStep;
          const clamped = clampCameraToWorld(currentCamera.x, newY, zoom);
          updateCameraPos(clamped);
          notifyViewportChange(clamped.x, clamped.y, zoom);
        }
        return;
      }

      if (e.key === 'PageUp') {
        e.preventDefault();
        stopMomentum();
        const newY = currentCamera.y + pageStep;
        const clamped = clampCameraToWorld(currentCamera.x, newY, zoom);
