      viewportBounds,
      tasks,
      clampCameraToWorld,
      animateZoomTo,
      updateCameraPos,
      notifyViewportChange,
      stopMomentum,
      stopZoomAnimation,
    ]
  );

  // Register keyboard event listener (F027 + F028)
  useEffect(() => {
