   153→    return null;
   154→  }
   155→
   156→  return (
   157→    <group>
   158→      {/* Heatmap cells */}
   159→      <instancedMesh
   160→        ref={meshRef}
   161→        args={[undefined, undefined, totalCells]}
   162→      >
   163→        <planeGeometry args={[1, 1]} />
