/**
 * RBushSpatialIndex - High-Performance R-tree Implementation
 *
 * STATE-ARCH-001 Phase 2: Replaces SimpleSpatialIndex with O(log n) queries.
 *
 * RBush is a battle-tested R-tree implementation that provides:
 * - O(log n) viewport queries (vs O(n) for SimpleSpatialIndex)
 * - Optimized bulk loading for initial data
 * - Efficient nearest neighbor search
 *
 * Performance characteristics:
 * - load(): O(n log n) - but optimized bulk insert
 * - insert(): O(log n)
 * - remove(): O(n) - requires equality function
 * - queryViewport(): O(log n + k) where k = result count
 * - queryRadius(): O(log n + k)
 * - queryNearest(): O(log n)
 *
 * Expected improvements for 60k tasks:
 * - SimpleSpatialIndex: ~5ms per query
 * - RBushSpatialIndex: ~0.5ms per query (10x faster)
 *
 * @see https://github.com/mourner/rbush
 */

import RBush from 'rbush';
import type {
  ISpatialIndex,
  SpatialItem,
  SpatialIndexStats,
  SpatialQueryResult,
  ViewportBounds,
} from './types';
import { distanceToCenter } from './types';

/**
 * Extended SpatialItem for RBush compatibility.
 * RBush requires minX, minY, maxX, maxY properties.
 */
interface RBushItem extends SpatialItem {
  // SpatialItem already has minX, minY, maxX, maxY, id
}

/**
 * RBush-based spatial index with O(log n) queries.
 */
export class RBushSpatialIndex implements ISpatialIndex {
  private tree: RBush<RBushItem>;
  private itemsById: Map<string, RBushItem> = new Map();
  private stats: SpatialIndexStats = {
    itemCount: 0,
  };

  constructor() {
    // RBush with default node size (9)
    // Higher node size = faster queries but slower inserts
    this.tree = new RBush<RBushItem>();
  }

  /**
   * Bulk load items into the R-tree.
   * This is significantly faster than inserting one by one.
   *
   * @param items - Array of items to index
   */
  load(items: SpatialItem[]): void {
    const startTime = performance.now();

    // Clear existing data
    this.tree.clear();
    this.itemsById.clear();

    // Build the lookup map
    for (const item of items) {
      this.itemsById.set(item.id, item as RBushItem);
    }

    // Bulk load into R-tree (optimized)
    this.tree.load(items as RBushItem[]);

    this.stats.itemCount = items.length;
    this.stats.lastBuildTimeMs = performance.now() - startTime;

    // Log performance in development
    if (import.meta.env.DEV) {
      console.log(
        `[RBushSpatialIndex] Loaded ${items.length} items in ${this.stats.lastBuildTimeMs.toFixed(2)}ms`
      );
    }
  }

  /**
   * Insert a single item.
   * Use sparingly - bulk load is more efficient.
   */
  insert(item: SpatialItem): void {
    const rbushItem = item as RBushItem;
    this.tree.insert(rbushItem);
    this.itemsById.set(item.id, rbushItem);
    this.stats.itemCount = this.itemsById.size;
  }

  /**
   * Remove an item by ID.
   * Note: RBush remove requires the exact object reference or equality function.
   */
  remove(id: string): boolean {
    const item = this.itemsById.get(id);
    if (!item) return false;

    // RBush.remove with equality function
    this.tree.remove(item, (a, b) => a.id === b.id);
    this.itemsById.delete(id);
    this.stats.itemCount = this.itemsById.size;
    return true;
  }

  /**
   * Clear all items.
   */
  clear(): void {
    this.tree.clear();
    this.itemsById.clear();
    this.stats.itemCount = 0;
  }

  /**
   * Query items within viewport bounds.
   * This is O(log n + k) where k = result count.
   *
   * @param bounds - Viewport rectangle in world coordinates
   * @returns Array of item IDs within bounds
   */
  queryViewport(bounds: ViewportBounds): string[] {
    const startTime = performance.now();

    // RBush.search returns all items intersecting the bounds
    const results = this.tree.search({
      minX: bounds.minX,
      minY: bounds.minY,
      maxX: bounds.maxX,
      maxY: bounds.maxY,
    });

    this.stats.lastQueryTimeMs = performance.now() - startTime;
    this.stats.lastQueryResultCount = results.length;

    return results.map(item => item.id);
  }

  /**
   * Query items within a circular region.
   *
   * Strategy: First use R-tree to get bounding box results,
   * then filter by actual circle intersection.
   */
  queryRadius(x: number, y: number, radius: number): string[] {
    const startTime = performance.now();

    // First, get all items in bounding square
    const candidates = this.tree.search({
      minX: x - radius,
      minY: y - radius,
      maxX: x + radius,
      maxY: y + radius,
    });

    // Then filter by actual circle intersection
    const radiusSq = radius * radius;
    const results: string[] = [];

    for (const item of candidates) {
      // Find closest point on rectangle to circle center
      const closestX = Math.max(item.minX, Math.min(x, item.maxX));
      const closestY = Math.max(item.minY, Math.min(y, item.maxY));

      const distSq = (x - closestX) ** 2 + (y - closestY) ** 2;
      if (distSq <= radiusSq) {
        results.push(item.id);
      }
    }

    this.stats.lastQueryTimeMs = performance.now() - startTime;
    this.stats.lastQueryResultCount = results.length;

    return results;
  }

  /**
   * Find the nearest item to a point.
   *
   * Strategy: Use expanding search - start with small radius,
   * expand until we find at least one item.
   */
  queryNearest(x: number, y: number, maxDistance?: number): SpatialQueryResult | null {
    const startTime = performance.now();

    // Start with a reasonable initial radius
    let radius = 50;
    const maxRadius = maxDistance ?? 10000;
    let nearest: SpatialQueryResult | null = null;
    let minDist = Infinity;

    // Expand search radius until we find something
    while (radius <= maxRadius && nearest === null) {
      const candidates = this.tree.search({
        minX: x - radius,
        minY: y - radius,
        maxX: x + radius,
        maxY: y + radius,
      });

      for (const item of candidates) {
        const dist = distanceToCenter(x, y, item);
        if (dist < minDist && dist <= maxRadius) {
          minDist = dist;
          nearest = {
            id: item.id,
            distance: dist,
          };
        }
      }

      // Expand radius
      radius *= 2;
    }

    this.stats.lastQueryTimeMs = performance.now() - startTime;
    this.stats.lastQueryResultCount = nearest ? 1 : 0;

    return nearest;
  }

  /**
   * Get performance statistics.
   */
  getStats(): SpatialIndexStats {
    return { ...this.stats };
  }

  /**
   * Get an item by ID (useful for debugging).
   */
  getItem(id: string): SpatialItem | undefined {
    return this.itemsById.get(id);
  }

  /**
   * Get all items (useful for debugging).
   */
  getAllItems(): SpatialItem[] {
    return Array.from(this.itemsById.values());
  }

  /**
   * Get the underlying R-tree (for advanced usage).
   */
  getTree(): RBush<RBushItem> {
    return this.tree;
  }
}

/**
 * Create a new RBushSpatialIndex instance.
 * Factory function for consistent API.
 */
export function createRBushSpatialIndex(): ISpatialIndex {
  return new RBushSpatialIndex();
}

