   279→/**
   280→ * Grid lines using InstancedMesh (OPTIMIZED - single draw call)
   281→ * Previously: ~251 individual meshes = 251 draw calls
   282→ * Now: 2 InstancedMesh = 2 draw calls
   283→ */
   284→function GridLines({
   285→  totalDays,
   286→  trainCount,
   287→  opacity = 1,
   288→  viewportBounds,
   289→}: {
   290→  totalDays: number;
   291→  trainCount: number;
   292→  opacity?: number;
   293→  viewportBounds?: ViewportBounds;
   294→}) {
   295→  const totalWidth = totalDays * pxPerDay;
   296→  const totalHeight = trainCount * pxPerTrain;
   297→
   298→  // Horizontal grid lines (train boundaries) - using InstancedMesh
   299→  const hMeshRef = useRef<InstancedMesh>(null);
   300→  const hTempObject = useMemo(() => new Object3D(), []);
   301→
   302→  // Vertical grid lines (week boundaries) - using InstancedMesh
   303→  const vMeshRef = useRef<InstancedMesh>(null);
   304→  const vTempObject = useMemo(() => new Object3D(), []);
   305→
   306→  // Calculate visible horizontal lines based on viewport
   307→  const visibleHLines = useMemo(() => {
   308→    if (!viewportBounds) {
   309→      return Array.from({ length: trainCount + 1 }, (_, i) => i);
   310→    }
   311→    const minTrainIndex = Math.max(0, Math.floor(-viewportBounds.maxY / pxPerTrain) - 1);
   312→    const maxTrainIndex = Math.min(trainCount, Math.ceil(-viewportBounds.minY / pxPerTrain) + 1);
   313→    return Array.from({ length: maxTrainIndex - minTrainIndex + 1 }, (_, i) => minTrainIndex + i);
   314→  }, [trainCount, viewportBounds]);
   315→
   316→  // Calculate visible vertical lines (weeks) based on viewport
   317→  const visibleVLines = useMemo(() => {
   318→    if (!viewportBounds) {
   319→      const lines = [];
   320→      for (let day = 0; day <= totalDays; day += 7) {
   321→        lines.push(day);
   322→      }
   323→      return lines.slice(0, 200);
   324→    }
   325→    const minDay = Math.max(0, Math.floor(viewportBounds.minX / pxPerDay / 7) * 7 - 7);
   326→    const maxDay = Math.min(totalDays, Math.ceil(viewportBounds.maxX / pxPerDay / 7) * 7 + 7);
   327→    const lines = [];
   328→    for (let day = minDay; day <= maxDay; day += 7) {
   329→      lines.push(day);
   330→    }
   331→    return lines;
   332→  }, [totalDays, viewportBounds]);
   333→
   334→  // Update horizontal lines InstancedMesh
   335→  useEffect(() => {
   336→    if (!hMeshRef.current || visibleHLines.length === 0) return;
   337→
   338→    const mesh = hMeshRef.current;
   339→    visibleHLines.forEach((trainIndex, i) => {
   340→      hTempObject.position.set(totalWidth / 2, -trainIndex * pxPerTrain, -0.05);
   341→      hTempObject.scale.set(totalWidth, 1, 1);
   342→      hTempObject.updateMatrix();
   343→      mesh.setMatrixAt(i, hTempObject.matrix);
   344→    });
   345→    mesh.instanceMatrix.needsUpdate = true;
   346→  }, [visibleHLines, totalWidth, hTempObject]);
   347→
   348→  // Update vertical lines InstancedMesh
   349→  useEffect(() => {
   350→    if (!vMeshRef.current || visibleVLines.length === 0) return;
   351→
   352→    const mesh = vMeshRef.current;
   353→    visibleVLines.forEach((day, i) => {
   354→      const isMajor = day % 30 === 0;
   355→      vTempObject.position.set(day * pxPerDay, -totalHeight / 2, -0.05);
   356→      vTempObject.scale.set(isMajor ? 1.5 : 1, totalHeight, 1);
   357→      vTempObject.updateMatrix();
   358→      mesh.setMatrixAt(i, vTempObject.matrix);
   359→      mesh.setColorAt(i, new Color(isMajor ? GRID_COLOR_MAJOR : GRID_COLOR_MINOR));
   360→    });
   361→    mesh.instanceMatrix.needsUpdate = true;
   362→    if (mesh.instanceColor) {
   363→      mesh.instanceColor.needsUpdate = true;
   364→    }
   365→  }, [visibleVLines, totalHeight, vTempObject]);
   366→
   367→  return (
   368→    <group>
   369→      {/* Horizontal lines - InstancedMesh */}
   370→      {visibleHLines.length > 0 && (
   371→        <instancedMesh ref={hMeshRef} args={[undefined, undefined, visibleHLines.length]}>
   372→          <planeGeometry args={[1, 1]} />
   373→          <meshBasicMaterial color={GRID_COLOR_MAJOR} transparent opacity={0.5 * opacity} />
   374→        </instancedMesh>
   375→      )}
   376→
   377→      {/* Vertical lines - InstancedMesh */}
   378→      {visibleVLines.length > 0 && (
   379→        <instancedMesh ref={vMeshRef} args={[undefined, undefined, visibleVLines.length]}>
   380→          <planeGeometry args={[1, 1]} />
   381→          <meshBasicMaterial transparent opacity={0.4 * opacity} />
   382→        </instancedMesh>
   383→      )}
   384→    </group>
   385→  );
   386→}
   387→
   388→/**
   389→ * Row backgrounds using InstancedMesh (OPTIMIZED - single draw call)
   390→ * Previously: 50 individual meshes = 50 draw calls
   391→ * Now: 1 InstancedMesh = 1 draw call
   392→ */
   393→function RowBackgrounds({
   394→  trainCount,
   395→  totalDays,
   396→  opacity = 1,
   397→  viewportBounds,
   398→}: {
   399→  trainCount: number;
   400→  totalDays: number;
   401→  opacity?: number;
   402→  viewportBounds?: ViewportBounds;
   403→}) {
   404→  const totalWidth = totalDays * pxPerDay;
   405→  const meshRef = useRef<InstancedMesh>(null);
   406→  const tempObject = useMemo(() => new Object3D(), []);
   407→
   408→  // Calculate visible rows based on viewport
   409→  const visibleRows = useMemo(() => {
   410→    if (!viewportBounds) {
   411→      return Array.from({ length: trainCount }, (_, i) => i);
   412→    }
   413→    const minTrainIndex = Math.max(0, Math.floor(-viewportBounds.maxY / pxPerTrain) - 1);
   414→    const maxTrainIndex = Math.min(trainCount - 1, Math.ceil(-viewportBounds.minY / pxPerTrain) + 1);
   415→    return Array.from({ length: maxTrainIndex - minTrainIndex + 1 }, (_, i) => minTrainIndex + i);
   416→  }, [trainCount, viewportBounds]);
   417→
   418→  useEffect(() => {
   419→    if (!meshRef.current || visibleRows.length === 0) return;
   420→
   421→    const mesh = meshRef.current;
   422→    visibleRows.forEach((trainIndex, i) => {
   423→      tempObject.position.set(totalWidth / 2, -trainIndex * pxPerTrain - pxPerTrain / 2, -0.1);
   424→      tempObject.scale.set(totalWidth, pxPerTrain, 1);
   425→      tempObject.updateMatrix();
   426→      mesh.setMatrixAt(i, tempObject.matrix);
   427→      mesh.setColorAt(i, new Color(trainIndex % 2 === 0 ? ROW_BG_EVEN : ROW_BG_ODD));
   428→    });
   429→    mesh.instanceMatrix.needsUpdate = true;
   430→    if (mesh.instanceColor) {
   431→      mesh.instanceColor.needsUpdate = true;
   432→    }
   433→  }, [visibleRows, totalWidth, tempObject]);
   434→
   435→  if (visibleRows.length === 0) return null;
   436→
   437→  return (
   438→    <instancedMesh ref={meshRef} args={[undefined, undefined, visibleRows.length]}>
   439→      <planeGeometry args={[1, 1]} />
   440→      <meshBasicMaterial transparent opacity={0.5 * opacity} />
   441→    </instancedMesh>
   442→  );
   443→}
   444→
   445→// Dependency line color
   446→const DEPENDENCY_LINE_COLOR = '#8b5cf6'; // Purple-500 for visibility
   447→const DEPENDENCY_ARROW_COLOR = '#7c3aed'; // Purple-600 for arrow heads
   448→
   449→/**
   450→ * Dependency Lines between tasks (F023)
   451→ *
   452→ * Renders curved lines from predecessor task to dependent task with arrow heads.
   453→ * Only renders dependencies where both tasks are in the visible set.
   454→ */
   455→function DependencyLines({
   456→  tasks,
   457→  opacity = 1,
   458→  viewportBounds: _viewportBounds,
   459→}: {
   460→  tasks: TaskRender[];
   461→  opacity?: number;
   462→  viewportBounds?: ViewportBounds;
   463→}) {
   464→  // Build a map of task ID to task for quick lookup
   465→  const taskMap = useMemo(() => {
   466→    return new Map(tasks.map((t) => [t.id, t]));
   467→  }, [tasks]);
   468→
   469→  // Find dependencies where both predecessor and dependent are visible
   470→  const dependencies = useMemo(() => {
   471→    const deps: Array<{ from: TaskRender; to: TaskRender }> = [];
   472→
   473→    for (const task of tasks) {
   474→      if (task.predecessorId) {
   475→        const predecessor = taskMap.get(task.predecessorId);
   476→        if (predecessor) {
   477→          deps.push({ from: predecessor, to: task });
   478→        }
   479→      }
   480→    }
   481→
   482→    return deps;
   483→  }, [tasks, taskMap]);
   484→
   485→  // Don't render during low opacity transitions (performance)
   486→  if (opacity < 0.3 || dependencies.length === 0) return null;
   487→
   488→  return (
   489→    <group>
   490→      {dependencies.map(({ from, to }, _index) => {
   491→        // Calculate connection points
   492→        // From: right edge of predecessor task (end)
   493→        const fromX = (from.startDay + from.duration) * pxPerDay;
   494→        const fromY = -from.trainIndex * pxPerTrain - pxPerTrain / 2;
   495→
   496→        // To: left edge of dependent task (start)
   497→        const toX = to.startDay * pxPerDay;
   498→        const toY = -to.trainIndex * pxPerTrain - pxPerTrain / 2;
   499→
   500→        // Create curved path using bezier-like points
   501→        const isSameRow = from.trainIndex === to.trainIndex;
   502→        const midX = (fromX + toX) / 2;
   503→
   504→        // Control points for curve
   505→        let points: Vector3[];
   506→        if (isSameRow) {
   507→          // Same row: simple horizontal line with slight vertical offset to avoid overlap
   508→          const offsetY = 8;
   509→          points = [
   510→            new Vector3(fromX, fromY + offsetY, 0.3),
   511→            new Vector3(midX, fromY + offsetY + 5, 0.3),
   512→            new Vector3(toX, toY + offsetY, 0.3),
   513→          ];
   514→        } else {
   515→          // Different rows: curved path
   516→          const controlOffset = Math.abs(toY - fromY) * 0.3;
   517→          points = [
   518→            new Vector3(fromX, fromY, 0.3),
   519→            new Vector3(fromX + controlOffset, fromY, 0.3),
   520→            new Vector3(midX, (fromY + toY) / 2, 0.3),
   521→            new Vector3(toX - controlOffset, toY, 0.3),
   522→            new Vector3(toX, toY, 0.3),
   523→          ];
   524→        }
   525→
   526→        // Arrow head points (triangle at the destination)
   527→        const arrowSize = 6;
   528→        const lastPoint = points[points.length - 1];
   529→        const secondLastPoint = points[points.length - 2];
   530→
   531→        // Direction vector for arrow
   532→        const direction = new Vector3().subVectors(lastPoint, secondLastPoint).normalize();
   533→        const perpendicular = new Vector3(-direction.y, direction.x, 0);
   534→
   535→        const arrowTip = lastPoint.clone();
   536→        const arrowBase1 = lastPoint.clone().sub(direction.clone().multiplyScalar(arrowSize)).add(perpendicular.clone().multiplyScalar(arrowSize / 2));
   537→        const arrowBase2 = lastPoint.clone().sub(direction.clone().multiplyScalar(arrowSize)).sub(perpendicular.clone().multiplyScalar(arrowSize / 2));
   538→
   539→        const arrowPoints = [
   540→          arrowTip,
   541→          arrowBase1,
   542→          arrowBase2,
   543→          arrowTip, // Close the triangle
   544→        ];
   545→
   546→        const key = `dep-${from.id}-${to.id}`;
   547→
   548→        return (
   549→          <group key={key}>
   550→            {/* Main dependency line */}
   551→            <Line
   552→              points={points}
   553→              color={DEPENDENCY_LINE_COLOR}
   554→              lineWidth={2}
   555→              opacity={opacity * 0.8}
   556→              transparent
   557→            />
   558→            {/* Arrow head */}
   559→            <Line
   560→              points={arrowPoints}
   561→              color={DEPENDENCY_ARROW_COLOR}
   562→              lineWidth={2}
   563→              opacity={opacity}
   564→              transparent
   565→            />
   566→          </group>
   567→        );
   568→      })}
   569→    </group>
   570→  );
   571→}
   572→
   573→/**
   574→ * Focus ring effect layer (F021)
   575→ * Renders a ring around the focused task for accessibility
   576→ */
   577→function FocusRing({
   578→  tasks,
   579→  focusedTaskId,
   580→  opacity = 1,
   581→}: {
   582→  tasks: TaskRender[];
   583→  focusedTaskId: string | null;
   584→  opacity?: number;
   585→}) {
   586→  const focusedTask = useMemo(
   587→    () => (focusedTaskId ? tasks.find((t) => t.id === focusedTaskId) : null),
   588→    [tasks, focusedTaskId]
   589→  );
   590→
   591→  const meshRef = useRef<InstancedMesh>(null);
   592→  const tempObject = useMemo(() => new Object3D(), []);
   593→
   594→  useEffect(() => {
   595→    if (!meshRef.current) return;
   596→
   597→    const mesh = meshRef.current;
   598→
   599→    if (focusedTask) {
   600→      const width = focusedTask.duration * pxPerDay + 6;
   601→      const height = CARD_HEIGHT + 6;
   602→      const x = focusedTask.startDay * pxPerDay + (focusedTask.duration * pxPerDay) / 2;
   603→      const y = -focusedTask.trainIndex * pxPerTrain - pxPerTrain / 2;
   604→      const z = 0.12;
   605→
   606→      tempObject.position.set(x, y, z);
   607→      tempObject.scale.set(width, height, 1);
   608→      tempObject.updateMatrix();
   609→      mesh.setMatrixAt(0, tempObject.matrix);
   610→    } else {
   611→      // Hide the ring by scaling to zero
   612→      tempObject.scale.set(0, 0, 1);
   613→      tempObject.updateMatrix();
   614→      mesh.setMatrixAt(0, tempObject.matrix);
   615→    }
   616→
